import{_ as e,o,c as l,ae as r}from"./chunks/framework.CGWemxwz.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),t={name:"faq.md"};function i(d,a,h,c,n,s){return o(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="基础问题" tabindex="-1">基础问题 <a class="header-anchor" href="#基础问题" aria-label="Permalink to &quot;基础问题&quot;">​</a></h2><h3 id="q-napcat-没反应" tabindex="-1">Q：NapCat 没反应？ <a class="header-anchor" href="#q-napcat-没反应" aria-label="Permalink to &quot;Q：NapCat 没反应？&quot;">​</a></h3><p>检查以下几项：</p><ol><li><code>APIURL</code> 是否能访问（浏览器打开试试）</li><li><code>SecretKey</code> 是否填写正确</li><li><code>DefaultGroupId</code> 是否填写正确</li><li>NapCat 是否正常运行</li></ol><h3 id="q-怎么知道插件加载成功了" tabindex="-1">Q：怎么知道插件加载成功了？ <a class="header-anchor" href="#q-怎么知道插件加载成功了" aria-label="Permalink to &quot;Q：怎么知道插件加载成功了？&quot;">​</a></h3><p>服务器启动时控制台会输出 xf-push 启动横幅，QQ 群也会收到启动通知。</p><h3 id="q-插件占用服务器资源吗" tabindex="-1">Q：插件占用服务器资源吗？ <a class="header-anchor" href="#q-插件占用服务器资源吗" aria-label="Permalink to &quot;Q：插件占用服务器资源吗？&quot;">​</a></h3><p>几乎不占用。插件只在事件触发时执行推送，大部分时间处于等待状态。</p><hr><h2 id="配置问题" tabindex="-1">配置问题 <a class="header-anchor" href="#配置问题" aria-label="Permalink to &quot;配置问题&quot;">​</a></h2><h3 id="q-消息不聚合" tabindex="-1">Q：消息不聚合？ <a class="header-anchor" href="#q-消息不聚合" aria-label="Permalink to &quot;Q：消息不聚合？&quot;">​</a></h3><p>确认以下配置：</p><ul><li><code>Batching.Enable = true</code></li><li><code>PlayerNotify.Events</code> 开启了对应事件</li></ul><h3 id="q-想推送到多个群怎么办" tabindex="-1">Q：想推送到多个群怎么办？ <a class="header-anchor" href="#q-想推送到多个群怎么办" aria-label="Permalink to &quot;Q：想推送到多个群怎么办？&quot;">​</a></h3><p>使用专业版 xf-pushplus，支持多 QQ 群同时推送。</p><h3 id="q-kook-和-discord-怎么配置" tabindex="-1">Q：KOOK 和 Discord 怎么配置？ <a class="header-anchor" href="#q-kook-和-discord-怎么配置" aria-label="Permalink to &quot;Q：KOOK 和 Discord 怎么配置？&quot;">​</a></h3><p>KOOK 需要填写 Bot Token 和频道 ID。 Discord 只需要填 Webhook URL，在频道设置 → 整合 → Webhook 里创建。</p><hr><h2 id="技术问题" tabindex="-1">技术问题 <a class="header-anchor" href="#技术问题" aria-label="Permalink to &quot;技术问题&quot;">​</a></h2><h3 id="q-服务器重启后推送通知没收到" tabindex="-1">Q：服务器重启后推送通知没收到？ <a class="header-anchor" href="#q-服务器重启后推送通知没收到" aria-label="Permalink to &quot;Q：服务器重启后推送通知没收到？&quot;">​</a></h3><p>检查服务器重启时 NapCat 是否也重启了，确认 NapCat 服务正常运行。</p><h3 id="q-定时公告没发出来" tabindex="-1">Q：定时公告没发出来？ <a class="header-anchor" href="#q-定时公告没发出来" aria-label="Permalink to &quot;Q：定时公告没发出来？&quot;">​</a></h3><ol><li>确认 <code>ScheduledPush.Enable = true</code></li><li>确认对应 <code>Job.Enabled = true</code></li><li>检查 Cron 表达式是否正确</li></ol><h3 id="q-限流了怎么办" tabindex="-1">Q：限流了怎么办？ <a class="header-anchor" href="#q-限流了怎么办" aria-label="Permalink to &quot;Q：限流了怎么办？&quot;">​</a></h3><p><code>RateLimit</code> 配置项可以调整 <code>MaxRequests</code> 和 <code>WindowMs</code>。</p><hr><h2 id="版本信息" tabindex="-1">版本信息 <a class="header-anchor" href="#版本信息" aria-label="Permalink to &quot;版本信息&quot;">​</a></h2><ul><li>当前版本：xf-push v1.0.16</li><li>专业版：xf-pushplus v2.0.0</li><li>插件作者：君临 | QQ：226666429</li></ul>',29)])])}const p=e(t,[["render",i]]);export{u as __pageData,p as default};
